__kernel void hotspotOpt1(
    __global float *pIn,
    __global float *tIn,
    __global float *tOut,
    float stepDivCap,
    int numCols,
    int numRows,
    int layers,
    float ce,
    float cw,
    float cn,
    float cs,
    float ct,
    float cb,
    float cc)
{
    int x = get_global_id(0);
    int y = get_global_id(1);
    int z;

    if (x >= numCols || y >= numRows) return;

    for (z = 0; z < layers; z++) {
        int c = x + y * numCols + z * numCols * numRows;

        int w = (0 == x) ? c : c - 1;
        int e = (numCols - 1 == x) ? c : c + 1;
        int n = (0 == y) ? c : c - numCols;
        int s = (numRows - 1 == y) ? c : c + numCols;
        int b = (0 == z) ? c : c - numCols * numRows;
        int t = (layers - 1 == z) ? c : c + numCols * numRows;

        tOut[c] = cc * tIn[c] + cw * tIn[w] + ce * tIn[e]
                + cs * tIn[s] + cn * tIn[n] + cb * tIn[b] + ct * tIn[t]
                + stepDivCap * pIn[c] + ct * 80.0f;
    }
}
